{"code": "import json
import re

# Get books file
books_file = locals()['var_functions.query_db:10']

# Load books data
with open(books_file, 'r') as f:
    books_data = json.load(f)

# Debug year extraction in detail for all books
successful_extractions = 0
failed_books = []
book_years = {}

for i, book in enumerate(books_data):
    details = book.get('details', '')
    book_id = book['book_id']

    if not details:
        failed_books.append({'book_id': book_id, 'reason': 'no details'})
        continue

    # Try multiple regex patterns
    patterns = [
        r'\b(19\d{2}|20\d{2})\b',
        r'(19\d{2}|20\d{2})',
        r'published[^\d]*(\d{4})'  # Case insensitive might help
    ]

    year_found = None
    for pattern in patterns:
        year_matches = re.findall(pattern, details, re.IGNORECASE)
        if year_matches:
            year_found = year_matches[0]

            # If we get a tuple (from groups), take the first non-empty
            if isinstance(year_found, tuple):
                year_found = next((y for y in year_found if y), None)

            if year_found:
                try:
                    year = int(year_found)
                    if 1900 <= year <= 2023:
                        book_years[book_id] = year
                        successful_extractions += 1
                        break
                except:
                    continue

    if not year_found:
        failed_books.append({
            'book_id': book_id,
            'details_start': details[:200] if details else 'EMPTY',
            'reason': 'no year match'
        })

print('__RESULT__:')
print(json.dumps({
    'total_books': len(books_data),
    'successful_extractions': successful_extractions,
    'failed_books_sample': failed_books[:5],
    'successful_sample': list(book_years.items())[:5]
}))"}
